/// 解析 init 进程的启动参数。
///
/// 如果 args[0] 是特殊的测试运行器标记（`@xjc-test-runner`），
/// 则 args[1] 是一个内嵌的 shell 脚本内容。此函数将其拼接为
/// `/bin/busybox sh -c "<脚本内容>"` 的形式，供 exec 使用。
fn resolve_init_args(args: &[String]) -> Vec<String> {
    if args.first().map(String::as_str) != Some(TEST_RUNNER_ENTRY) {
        return args.to_vec();
    }

    let script = args.get(1).cloned().unwrap_or_default();
    let fs = FS_CONTEXT.lock();
    let runner = TEST_RUNNER_CANDIDATES
        .iter()
        .copied()
        .find(|path| fs.resolve(path).is_ok())
        .unwrap_or("/bin/sh");
    drop(fs);

    let mut resolved = if runner.ends_with("/sh") {
        vec![runner.to_string(), "-c".to_string(), script]
    } else {
        vec![
            runner.to_string(),
            "sh".to_string(),
            "-c".to_string(),
            script,
        ]
    };
    resolved.extend(args.iter().skip(2).cloned());
    resolved

